PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>

SELECT (MAX(?dur) AS ?maxDuration) WHERE {
  VALUES ?series { wd:Q56692089 wd:Q14870260 wd:Q3511178 }
  ?series wdt:P527 ?game .
  ?game wdt:P710 wd:Q213959 .  # Boston Red Sox participant
  ?game wdt:P2078 ?durationAmount .
  ?durationAmount wikibase:quantityAmount ?durStr ;
                   wikibase:quantityUnit wd:Q7727 .  # minute
  BIND(xsd:integer(?durStr) AS ?dur)
}
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (MAX(?duration) AS ?maxDuration)
WHERE {
  VALUES ?series { wd:Q56692089 wd:Q14870260 wd:Q3511178 }
  ?series wdt:P527 ?game .
  ?game wdt:P710 wd:Q213959 .
  ?game wdt:P2047 ?durationQuantity .
  ?durationQuantity 
    wikibase:quantityAmount ?amountStr ;
    wikibase:quantityUnit ?unit .

  BIND(xsd:float(?amountStr) AS ?amount)
  BIND(
    IF(?unit = wd:Q7727, ?amount, 
      IF(?unit = wd:Q573, ?amount * 60, 
        IF(?unit = wd:Q7764, ?amount / 60, 0)
      )
    ) AS ?duration
  )
  FILTER(?duration > 0)
}
ORDER BY DESC(?duration)
LIMIT 1

